  6тЖТpackage kotlinx.datetime.internal.format.parser
  7тЖТ
  8тЖТimport kotlin.jvm.JvmInline
  9тЖТ
 10тЖТ/**
 11тЖТ * Describes the commands that the parser must execute, in two portions:
 12тЖТ * * [operations], which are executed in order, and
 13тЖТ * * [followedBy], which are executed *in parallel* after [operations].
 14тЖТ *
 15тЖТ * An example of a [ParserStructure]:
 16тЖТ * ```
 17тЖТ * // number - dash - number - dash - number
 18тЖТ * //        |
 19тЖТ * //        \
 20тЖТ * //         letter 'W' - number
 21тЖТ * ParserStructure(
 22тЖТ *   listOf(numberParser),
 23тЖТ *   listOf(
 24тЖТ *     ParserStructure(
 25тЖТ *       listOf(stringParser("-"), numberParser, stringParser("-"), numberParser),
 26тЖТ *       emptyList()
 27тЖТ *     ),
 28тЖТ *     ParserStructure(
 29тЖТ *       listOf(stringParser("W"), numberParser),
 30тЖТ *       emptyList()
 31тЖТ *     ),
 32тЖТ *   )
 33тЖТ * )
 34тЖТ * ```
 35тЖТ */
 36тЖТinternal class ParserStructure<in Output>(
 37тЖТ    val operations: List<ParserOperation<Output>>,
 38тЖТ    val followedBy: List<ParserStructure<Output>>,
 39тЖТ) {
 40тЖТ    override fun toString(): String =
 41тЖТ        "${operations.joinToString(", ")}(${followedBy.joinToString(";")})"
 42тЖТ}
 43тЖТ
 44тЖТ// TODO: O(size of the resulting parser ^ 2), but can be O(size of the resulting parser)
 45тЖТinternal fun <T> List<ParserStructure<T>>.concat(): ParserStructure<T> {
 46тЖТ    fun <T> ParserStructure<T>.append(other: ParserStructure<T>): ParserStructure<T> = if (followedBy.isEmpty()) {
 47тЖТ        ParserStructure(operations + other.operations, other.followedBy)
 48тЖТ    } else {
 49тЖТ        ParserStructure(operations, followedBy.map { it.append(other) })
 50тЖТ    }
 51тЖТ    fun <T> ParserStructure<T>.simplify(): ParserStructure<T> {
 52тЖТ        val newOperations = mutableListOf<ParserOperation<T>>()
 53тЖТ        var currentNumberSpan: MutableList<NumberConsumer<T>>? = null
 54тЖТ        // joining together the number consumers in this parser before the first alternative
 55тЖТ        for (op in operations) {
 56тЖТ            if (op is NumberSpanParserOperation) {
 57тЖТ                if (currentNumberSpan != null) {
 58тЖТ                    currentNumberSpan.addAll(op.consumers)
 59тЖТ                } else {
 60тЖТ                    currentNumberSpan = op.consumers.toMutableList()
 61тЖТ                }
 62тЖТ            } else {
 63тЖТ                if (currentNumberSpan != null) {
 64тЖТ                    newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 65тЖТ                    currentNumberSpan = null
 66тЖТ                }
 67тЖТ                newOperations.add(op)
 68тЖТ            }
 69тЖТ        }
 70тЖТ        val mergedTails = followedBy.flatMap {
 71тЖТ            val simplified = it.simplify()
 72тЖТ            // parser `ParserStructure(emptyList(), p)` is equivalent to `p`,
 73тЖТ            // unless `p` is empty. For example, ((a|b)|(c|d)) is equivalent to (a|b|c|d).
 74тЖТ            // As a special case, `ParserStructure(emptyList(), emptyList())` represents a parser that recognizes an empty
 75тЖТ            // string. For example, (|a|b) is not equivalent to (a|b).
 76тЖТ            if (simplified.operations.isEmpty())
 77тЖТ                simplified.followedBy.ifEmpty { listOf(simplified) }
 78тЖТ            else
 79тЖТ                listOf(simplified)
 80тЖТ        }
 81тЖТ        return if (currentNumberSpan == null) {
 82тЖТ            // the last operation was not a number span, or it was a number span that we are allowed to interrupt
 83тЖТ            ParserStructure(newOperations, mergedTails)
 84тЖТ        } else if (mergedTails.none {
 85тЖТ                it.operations.firstOrNull()?.let { it is NumberSpanParserOperation } == true
 86тЖТ            }) {
 87тЖТ            // the last operation was a number span, but there are no alternatives that start with a number span.
 88тЖТ            newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 89тЖТ            ParserStructure(newOperations, mergedTails)
 90тЖТ        } else {
 91тЖТ            val newTails = mergedTails.map {
 92тЖТ                when (val firstOperation = it.operations.firstOrNull()) {
 93тЖТ                    is NumberSpanParserOperation -> {
 94тЖТ                        ParserStructure(
 95тЖТ                            listOf(NumberSpanParserOperation(currentNumberSpan + firstOperation.consumers)) + it.operations.drop(
 96тЖТ                                1
 97тЖТ                            ),
 98тЖТ                            it.followedBy
 99тЖТ                        )
100тЖТ                    }
101тЖТ
102тЖТ                    null -> ParserStructure(
103тЖТ                        listOf(NumberSpanParserOperation(currentNumberSpan)),
104тЖТ                        it.followedBy
105тЖТ                    )
106тЖТ
107тЖТ                    else -> ParserStructure(
108тЖТ                        listOf(NumberSpanParserOperation(currentNumberSpan)) + it.operations,
109тЖТ                        it.followedBy
110тЖТ                    )
111тЖТ                }
112тЖТ            }
113тЖТ            ParserStructure(newOperations, newTails)
114тЖТ        }
115тЖТ    }
116тЖТ    val naiveParser = foldRight(ParserStructure<T>(emptyList(), emptyList())) { parser, acc -> parser.append(acc) }
117тЖТ    return naiveParser.simplify()
118тЖТ}
