120тЖТinternal interface Copyable<Self> {
121тЖТ    fun copy(): Self
122тЖТ}
123тЖТ
124тЖТ@JvmInline
125тЖТinternal value class Parser<Output: Copyable<Output>>(
126тЖТ    private val commands: ParserStructure<Output>
127тЖТ) {
128тЖТ    /**
129тЖТ     * [startIndex] is the index of the first character that is not yet consumed.
130тЖТ     *
131тЖТ     * [allowDanglingInput] determines whether the match is only successful if the whole string after [startIndex]
132тЖТ     * is consumed.
133тЖТ     *
134тЖТ     * [onSuccess] is invoked as soon as some parsing attempt succeeds.
135тЖТ     * [onError] is invoked when some parsing attempt fails.
136тЖТ     */
137тЖТ    // Would be a great place to use the `Flow` from `kotlinx.coroutines` here instead of `onSuccess` and
138тЖТ    // `onError`, but alas.
139тЖТ    private inline fun parse(
140тЖТ        input: CharSequence,
141тЖТ        startIndex: Int,
142тЖТ        initialContainer: Output,
143тЖТ        allowDanglingInput: Boolean,
144тЖТ        onError: (ParseError) -> Unit,
145тЖТ        onSuccess: (Int, Output) -> Unit
146тЖТ    ) {
147тЖТ        val parseOptions = mutableListOf(ParserState(initialContainer, commands, startIndex))
148тЖТ        iterate_over_alternatives@while (true) {
149тЖТ            val state = parseOptions.removeLastOrNull() ?: break
150тЖТ            val output = state.output.copy()
151тЖТ            var inputPosition = state.inputPosition
152тЖТ            val parserStructure = state.parserStructure
153тЖТ            run parse_one_alternative@{
154тЖТ                for (ix in parserStructure.operations.indices) {
155тЖТ                    parserStructure.operations[ix].consume(output, input, inputPosition).match(
156тЖТ                        { inputPosition = it },
157тЖТ                        {
158тЖТ                            onError(it)
159тЖТ                            return@parse_one_alternative // continue@iterate_over_alternatives, if that were supported
160тЖТ                        }
161тЖТ                    )
162тЖТ                }
163тЖТ                if (parserStructure.followedBy.isEmpty()) {
164тЖТ                    if (allowDanglingInput || inputPosition == input.length) {
165тЖТ                        onSuccess(inputPosition, output)
166тЖТ                    } else {
167тЖТ                        onError(ParseError(inputPosition) { "There is more input to consume" })
168тЖТ                    }
169тЖТ                } else {
170тЖТ                    for (ix in parserStructure.followedBy.indices.reversed()) {
171тЖТ                        parseOptions.add(ParserState(output, parserStructure.followedBy[ix], inputPosition))
172тЖТ                    }
173тЖТ                }
174тЖТ            }
175тЖТ        }
176тЖТ    }
177тЖТ
178тЖТ    fun match(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output {
179тЖТ        val errors = mutableListOf<ParseError>()
180тЖТ        parse(input, startIndex, initialContainer, allowDanglingInput = false, { errors.add(it) }, { _, out -> return@match out })
181тЖТ        errors.sortByDescending { it.position }
182тЖТ        // `errors` can not be empty because each parser will have (successes + failures) >= 1, and here, successes == 0
183тЖТ        ParseException(errors.first()).let {
184тЖТ            for (error in errors.drop(1)) {
185тЖТ                it.addSuppressed(ParseException(error))
186тЖТ            }
187тЖТ            throw it
188тЖТ        }
189тЖТ    }
190тЖТ
191тЖТ    fun matchOrNull(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output? {
192тЖТ        parse(input, startIndex, initialContainer, allowDanglingInput = false, { }, { _, out -> return@matchOrNull out })
193тЖТ        return null
194тЖТ    }
195тЖТ
196тЖТ    private class ParserState<Output>(
197тЖТ        val output: Output,
198тЖТ        val parserStructure: ParserStructure<Output>,
199тЖТ        val inputPosition: Int,
200тЖТ    )
201тЖТ}
202тЖТ
203тЖТinternal class ParseException(error: ParseError) : Exception("Position ${error.position}: ${error.message()}")
