  6тЖТpackage kotlinx.datetime.internal.format
  7тЖТ
  8тЖТimport kotlinx.datetime.internal.format.formatter.*
  9тЖТimport kotlinx.datetime.internal.format.parser.*
 10тЖТ
 11тЖТinternal sealed interface FormatStructure<in T> {
 12тЖТ    fun parser(): ParserStructure<T>
 13тЖТ    fun formatter(): FormatterStructure<T>
 14тЖТ}
 15тЖТ
 16тЖТinternal class BasicFormatStructure<in T>(
 17тЖТ    val directive: FieldFormatDirective<T>
 18тЖТ) : NonConcatenatedFormatStructure<T> {
 19тЖТ    override fun toString(): String = "BasicFormatStructure($directive)"
 20тЖТ
 21тЖТ    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 22тЖТ    override fun hashCode(): Int = directive.hashCode()
 23тЖТ
 24тЖТ    override fun parser(): ParserStructure<T> = directive.parser()
 25тЖТ    override fun formatter(): FormatterStructure<T> = directive.formatter()
 26тЖТ}
 27тЖТ
 28тЖТinternal class ConstantFormatStructure<in T>(
 29тЖТ    val string: String
 30тЖТ) : NonConcatenatedFormatStructure<T> {
 31тЖТ    override fun toString(): String = "ConstantFormatStructure($string)"
 32тЖТ
 33тЖТ    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 34тЖТ    override fun hashCode(): Int = string.hashCode()
 35тЖТ
 36тЖТ    override fun parser(): ParserStructure<T> = ParserStructure(
 37тЖТ        operations = when {
 38тЖТ            string.isEmpty() -> emptyList()
 39тЖТ            else -> buildList {
 40тЖТ                val suffix = if (string[0].isDigit()) {
 41тЖТ                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isDigit() }))))
 42тЖТ                    string.dropWhile { it.isDigit() }
 43тЖТ                } else {
 44тЖТ                    string
 45тЖТ                }
 46тЖТ                if (suffix.isNotEmpty()) {
 47тЖТ                    if (suffix[suffix.length - 1].isDigit()) {
 48тЖТ                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isDigit() }))
 49тЖТ                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile { it.isDigit() }))))
 50тЖТ                    } else {
 51тЖТ                        add(PlainStringParserOperation(suffix))
 52тЖТ                    }
 53тЖТ                }
 54тЖТ            }
 55тЖТ        },
 56тЖТ        followedBy = emptyList()
 57тЖТ    )
 58тЖТ
 59тЖТ    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 60тЖТ}
 61тЖТ
 62тЖТinternal class SignedFormatStructure<in T>(
 63тЖТ    val format: FormatStructure<T>,
 64тЖТ    val withPlusSign: Boolean,
 65тЖТ) : NonConcatenatedFormatStructure<T> {
 66тЖТ
 67тЖТ    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 68тЖТ
 69тЖТ    init {
 70тЖТ        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 71тЖТ    }
 72тЖТ
 73тЖТ    override fun toString(): String = "SignedFormatStructure($format)"
 74тЖТ
 75тЖТ    override fun equals(other: Any?): Boolean =
 76тЖТ        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 77тЖТ
 78тЖТ    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 79тЖТ
 80тЖТ    override fun parser(): ParserStructure<T> = listOf(
 81тЖТ        ParserStructure(
 82тЖТ            operations = listOf(
 83тЖТ                SignParser(
 84тЖТ                    isNegativeSetter = { value, isNegative ->
 85тЖТ                        for (field in fieldSigns) {
 86тЖТ                            val wasNegative = field.isNegative.getter(value) == true
 87тЖТ                            // TODO: replacing `!=` with `xor` fails on JS
 88тЖТ                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 89тЖТ                        }
 90тЖТ                    },
 91тЖТ                    withPlusSign = withPlusSign,
 92тЖТ                    whatThisExpects = "sign for ${this.fieldSigns}"
 93тЖТ                )
 94тЖТ            ),
 95тЖТ            emptyList()
 96тЖТ        ), format.parser()
 97тЖТ    ).concat()
 98тЖТ
 99тЖТ    override fun formatter(): FormatterStructure<T> {
100тЖТ        val innerFormat = format.formatter()
101тЖТ        fun checkIfAllNegative(value: T): Boolean {
102тЖТ            var seenNonZero = false
103тЖТ            for (check in fieldSigns) {
104тЖТ                when {
105тЖТ                    check.isNegative.getter(value) == true -> seenNonZero = true
106тЖТ                    check.isZero(value) -> continue
107тЖТ                    else -> return false
108тЖТ                }
109тЖТ            }
110тЖТ            return seenNonZero
111тЖТ        }
112тЖТ        return SignedFormatter(
113тЖТ            innerFormat,
114тЖТ            ::checkIfAllNegative,
115тЖТ            withPlusSign
116тЖТ        )
117тЖТ    }
118тЖТ}
