120тЖТinternal class AlternativesParsingFormatStructure<in T>(
121тЖТ    val mainFormat: FormatStructure<T>,
122тЖТ    val formats: List<FormatStructure<T>>,
123тЖТ) : NonConcatenatedFormatStructure<T> {
124тЖТ    override fun toString(): String = "AlternativesParsing($formats)"
125тЖТ
126тЖТ    override fun equals(other: Any?): Boolean =
127тЖТ        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
128тЖТ
129тЖТ    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
130тЖТ
131тЖТ    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
132тЖТ        add(mainFormat.parser())
133тЖТ        for (format in formats) {
134тЖТ            add(format.parser())
135тЖТ        }
136тЖТ    })
137тЖТ
138тЖТ    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
139тЖТ}
140тЖТ
141тЖТinternal class OptionalFormatStructure<in T>(
142тЖТ    val onZero: String,
143тЖТ    val format: FormatStructure<T>,
144тЖТ) : NonConcatenatedFormatStructure<T> {
145тЖТ    override fun toString(): String = "Optional($onZero, $format)"
146тЖТ
147тЖТ    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148тЖТ        PropertyWithDefault.fromField(field)
149тЖТ    }
150тЖТ
151тЖТ    override fun equals(other: Any?): Boolean =
152тЖТ        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153тЖТ
154тЖТ    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155тЖТ
156тЖТ    override fun parser(): ParserStructure<T> = ParserStructure(
157тЖТ        operations = emptyList(),
158тЖТ        followedBy = listOf(
159тЖТ            format.parser(),
160тЖТ            listOf(
161тЖТ                ConstantFormatStructure<T>(onZero).parser(),
162тЖТ                ParserStructure(
163тЖТ                    listOf(
164тЖТ                        UnconditionalModification {
165тЖТ                            for (field in fields) {
166тЖТ                                field.assignDefault(it)
167тЖТ                            }
168тЖТ                        }
169тЖТ                    ),
170тЖТ                    emptyList()
171тЖТ                )
172тЖТ            ).concat()
173тЖТ        )
174тЖТ    )
175тЖТ
176тЖТ    override fun formatter(): FormatterStructure<T> {
177тЖТ        val formatter = format.formatter()
178тЖТ        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179тЖТ        return ConditionalFormatter(
180тЖТ            listOf(
181тЖТ                predicate::test to ConstantStringFormatterStructure(onZero),
182тЖТ                Truth::test to formatter
183тЖТ            )
184тЖТ        )
185тЖТ    }
186тЖТ
187тЖТ    private class PropertyWithDefault<in T, E> private constructor(
188тЖТ        private val accessor: Accessor<T, E>,
189тЖТ        private val defaultValue: E
190тЖТ    ) {
191тЖТ        companion object {
192тЖТ            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
193тЖТ                val default = field.defaultValue
194тЖТ                require(default != null) {
195тЖТ                    "The field '${field.name}' does not define a default value"
196тЖТ                }
197тЖТ                return PropertyWithDefault(field.accessor, default)
198тЖТ            }
199тЖТ        }
200тЖТ
201тЖТ        inline fun assignDefault(target: T) {
202тЖТ            accessor.trySetWithoutReassigning(target, defaultValue)
203тЖТ        }
204тЖТ
205тЖТ        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
206тЖТ    }
207тЖТ}
208тЖТ
209тЖТinternal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
210тЖТ
211тЖТinternal open class ConcatenatedFormatStructure<in T>(
212тЖТ    val formats: List<NonConcatenatedFormatStructure<T>>
213тЖТ) : FormatStructure<T> {
214тЖТ    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
215тЖТ
216тЖТ    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
217тЖТ
218тЖТ    override fun hashCode(): Int = formats.hashCode()
219тЖТ
220тЖТ    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
221тЖТ
222тЖТ    override fun formatter(): FormatterStructure<T> {
223тЖТ        val formatters = formats.map { it.formatter() }
224тЖТ        return if (formatters.size == 1) {
225тЖТ            formatters.single()
226тЖТ        } else {
227тЖТ            ConcatenatedFormatter(formatters)
228тЖТ        }
229тЖТ    }
230тЖТ}
231тЖТ
232тЖТinternal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
233тЖТ    ConcatenatedFormatStructure<T>(formats) {
234тЖТ    private val cachedFormatter: FormatterStructure<T> by lazy { super.formatter() }
235тЖТ    private val cachedParser: ParserStructure<T> by lazy { super.parser() }
236тЖТ
237тЖТ    override fun formatter(): FormatterStructure<T> = cachedFormatter
238тЖТ
239тЖТ    override fun parser(): ParserStructure<T> = cachedParser
240тЖТ}
241тЖТ
242тЖТprivate fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
243тЖТ    fun rec(format: FormatStructure<T>) {
244тЖТ        when (format) {
245тЖТ            is BasicFormatStructure -> add(format.directive)
246тЖТ            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
247тЖТ            is ConstantFormatStructure -> {}
248тЖТ            is SignedFormatStructure -> rec(format.format)
249тЖТ            is AlternativesParsingFormatStructure -> {
250тЖТ                rec(format.mainFormat); format.formats.forEach { rec(it) }
251тЖТ            }
252тЖТ
253тЖТ            is OptionalFormatStructure -> rec(format.format)
254тЖТ        }
255тЖТ    }
256тЖТ    rec(format)
257тЖТ}
