package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class ErrorMessageImprovementsTest {

    @Test
    fun testInputPreservationInValidationErrors() {
        // Test that validation errors include the original input
        val input = "2023-02-30" // Invalid day for February
        val exception = assertFailsWith<IllegalArgumentException> {
            LocalDate.parse(input)
        }
        assertTrue(exception.message!!.contains(input), 
            "Expected error message to contain input '$input', but got: ${exception.message}")
    }

    @Test
    fun testInputPreservationInTimeValidationErrors() {
        // Test that time validation errors include the original input
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val input = "23:30 AM" // Invalid: 23:00 cannot be AM
        val exception = assertFailsWith<IllegalArgumentException> {
            format.parse(input)
        }
        assertTrue(exception.message!!.contains(input), 
            "Expected error message to contain input '$input', but got: ${exception.message}")
        assertTrue(exception.message!!.contains("Inconsistent"), 
            "Expected error message to mention inconsistency, but got: ${exception.message}")
    }

    @Test
    fun testInputPreservationInUtcOffsetValidationErrors() {
        // Test that UtcOffset validation errors include the original input
        val input = "+25:00" // Invalid: offset too large
        val exception = assertFailsWith<IllegalArgumentException> {
            UtcOffset.parse(input)
        }
        assertTrue(exception.message!!.contains(input), 
            "Expected error message to contain input '$input', but got: ${exception.message}")
    }

    @Test
    fun testCapitalizationInExpectedOneOfErrors() {
        // Test that "Expected one of" uses lowercase 'o'
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val input = "12:30 XM" // Invalid AM/PM marker
        val exception = assertFailsWith<IllegalArgumentException> {
            format.parse(input)
        }
        // The error should say "Expected one of" not "Expected One of"
        val message = exception.message!!.lowercase()
        assertTrue(message.contains("expected") && message.contains("one of"), 
            "Expected error message to contain 'expected one of', but got: ${exception.message}")
    }

    @Test
    fun testInputPreservationInDateTimeComponentsErrors() {
        // Test with DateTimeComponents format
        val format = DateTimeComponents.Format {
            date(LocalDate.Formats.ISO)
            char('T')
            time(LocalTime.Formats.ISO)
        }
        val input = "2023-13-01T12:00:00" // Invalid month
        val exception = assertFailsWith<IllegalArgumentException> {
            format.parse(input).toLocalDate()
        }
        assertTrue(exception.message!!.contains(input), 
            "Expected error message to contain input '$input', but got: ${exception.message}")
    }

    @Test
    fun testValidInputStillWorks() {
        // Ensure valid parsing still works
        val date = LocalDate.parse("2023-02-28")
        assertEquals(2023, date.year)
        assertEquals(2, date.monthNumber)
        assertEquals(28, date.dayOfMonth)

        val time = LocalTime.parse("12:30:45")
        assertEquals(12, time.hour)
        assertEquals(30, time.minute)
        assertEquals(45, time.second)

        val offset = UtcOffset.parse("+05:30")
        assertEquals(5 * 3600 + 30 * 60, offset.totalSeconds)
    }
}
