 62тЖТinternal class SignedFormatStructure<in T>(
 63тЖТ    val format: FormatStructure<T>,
 64тЖТ    val withPlusSign: Boolean,
 65тЖТ) : NonConcatenatedFormatStructure<T> {
 66тЖТ
 67тЖТ    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 68тЖТ
