242тЖТprivate fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
243тЖТ    fun rec(format: FormatStructure<T>) {
244тЖТ        when (format) {
245тЖТ            is BasicFormatStructure -> add(format.directive)
246тЖТ            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
247тЖТ            is ConstantFormatStructure -> {}
248тЖТ            is SignedFormatStructure -> rec(format.format)
249тЖТ            is AlternativesParsingFormatStructure -> {
250тЖТ                rec(format.mainFormat); format.formats.forEach { rec(it) }
251тЖТ            }
252тЖТ
253тЖТ            is OptionalFormatStructure -> rec(format.format)
254тЖТ        }
255тЖТ    }
256тЖТ    rec(format)
